import{_ as o,o as a,c as e,a3 as n}from"./chunks/framework.DACwFHq9.js";const h=JSON.parse('{"title":"Embedding 测试","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/embedding-playground.md","filePath":"user-guide/tools/embedding-playground.md","lastUpdated":1778221347000}'),r={name:"user-guide/tools/embedding-playground.md"};function i(l,t,d,s,g,u){return a(),e("div",null,[...t[0]||(t[0]=[n(`<h1 id="embedding-测试" tabindex="-1">Embedding 测试 <a class="header-anchor" href="#embedding-测试" aria-label="Permalink to &quot;Embedding 测试&quot;">​</a></h1><blockquote><p>面向开发者的 Embedding API 交互式调试场 —— 让向量化模型不再&quot;黑盒&quot;。</p></blockquote><p>欢迎来到 <strong>Embedding 测试</strong> 工具。如果你正在做 RAG（检索增强生成）、语义搜索或任何与向量嵌入（Embedding）相关的工作，那么这个工具会成为你迭代模型选择、验证召回效果的好帮手。</p><p>你可以把它想象成 <strong>Embedding 模型的&quot;示波器&quot;</strong>——既能输出原始信号（原始 API 响应），也能做数据对比分析（语义距离排行榜），还能直接模拟完整的 RAG 检索链路。</p><hr><h2 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h2><p>在使用前，请确保你已经在应用的&quot;设置 &gt; LLM 配置&quot;中配置好了至少一个支持 Embedding 的模型服务（如 OpenAI <code>text-embedding-3-small</code>、本地部署的 <code>bge-m3</code> 等）。</p><h3 id="第一步-选择-embedding-模型" tabindex="-1">第一步：选择 Embedding 模型 <a class="header-anchor" href="#第一步-选择-embedding-模型" aria-label="Permalink to &quot;第一步：选择 Embedding 模型&quot;">​</a></h3><p>打开 Embedding 测试工具后，在顶部右侧的模型选择器中选中你配置好的 Embedding 模型。</p><blockquote><p>TODO: 截图 - 顶部模型选择器</p></blockquote><h3 id="第二步-选择一个测试模式" tabindex="-1">第二步：选择一个测试模式 <a class="header-anchor" href="#第二步-选择一个测试模式" aria-label="Permalink to &quot;第二步：选择一个测试模式&quot;">​</a></h3><p>工具提供了三个 Tab，你可以根据当前需求选择：</p><ul><li><strong>相似度对比</strong> —— 验证模型对语义相近/相远概念的区分能力</li><li><strong>检索模拟</strong> —— 搭建微型知识库，模拟 RAG 召回过程</li><li><strong>基础调试</strong> —— 查看原始 API 响应，验证模型接入是否正常</li></ul><p>建议新手先从 <strong>相似度对比</strong> 开始，感受 Embedding 模型的&quot;语义直觉&quot;。</p><hr><h2 id="功能详解" tabindex="-1">功能详解 <a class="header-anchor" href="#功能详解" aria-label="Permalink to &quot;功能详解&quot;">​</a></h2><h3 id="🎯-相似度对比" tabindex="-1">🎯 相似度对比 <a class="header-anchor" href="#🎯-相似度对比" aria-label="Permalink to &quot;🎯 相似度对比&quot;">​</a></h3><p>这是你快速评估 Embedding 模型语义理解能力的最佳入口。</p><p><strong>典型使用场景</strong>：</p><p>你正在对比 <code>text-embedding-3-small</code> 和 <code>text-embedding-3-large</code> 对中文语义的区分能力，想知道哪个模型更理解&quot;机器学习&quot;和&quot;神经网络&quot;之间的联系，又不会把&quot;红烧肉&quot;当成相关概念。</p><p><strong>操作步骤</strong>：</p><ol><li>在左侧&quot;对比设置&quot;区域，选择一种<strong>对比算法</strong>（默认余弦相似度，通常是最常用的语义指标）。</li><li>在&quot;基准文本&quot;编辑器中输入你关注的中心概念，例如 <code>&quot;计算机科学&quot;</code>。</li><li>在&quot;对比文本组&quot;中，列出一批你想测试的词汇或短句（系统已预置了 9 条示例文本，你可以随意增删改）。</li><li>点击 <strong>&quot;开始对比&quot;</strong>。</li><li>右侧&quot;语义相似度排行&quot;面板会立即按相似度从高到低展示结果。</li></ol><p><strong>结果解读</strong>：</p><p>每条结果卡片包含：</p><ul><li><strong>#排名</strong> —— 序号，从高到低排列</li><li><strong>相似度分数</strong> —— <code>0.0000</code> ~ <code>1.0000</code> 之间的数值，越接近 1 表示语义越相近</li><li><strong>背景进度条</strong> —— 可视化相似度百分比</li><li><strong>颜色编码</strong> —— 绿色（&gt; 0.8）高度相关、黄色（&gt; 0.5）中等相关、红色（≤ 0.5）低相关</li></ul><p>你可以点击结果面板右上角的复制按钮，一键将排行榜复制到剪贴板，方便分享或记录。</p><p><strong>💡 小技巧</strong>：你可以随时切换对比算法（余弦 / 欧氏 / 点积 / 曼哈顿），系统会自动基于已缓存的向量重新计算分数，无需重新请求 API。这让你能在同一组向量上直观对比不同距离指标的表现。</p><hr><h3 id="🗂️-检索模拟" tabindex="-1">🗂️ 检索模拟 <a class="header-anchor" href="#🗂️-检索模拟" aria-label="Permalink to &quot;🗂️ 检索模拟&quot;">​</a></h3><p>这是模拟 RAG 系统 <code>Retrieval</code> 阶段的最佳环境——无需搭建任何后端，纯前端即可体验完整的&quot;文档索引 → 查询召回&quot;流程。</p><p><strong>典型使用场景</strong>：</p><p>你想验证自己的知识库文档经过某个 Embedding 模型后，针对特定查询的召回效果。例如构建一个&quot;AI 工具库&quot;小知识库后，输入&quot;如何构建桌面应用&quot;看能否准确召回 Tauri/Rust 相关的文档。</p><p><strong>操作步骤</strong>：</p><h4 id="_1-构建知识库" tabindex="-1">1. 构建知识库 <a class="header-anchor" href="#_1-构建知识库" aria-label="Permalink to &quot;1. 构建知识库&quot;">​</a></h4><p>在左侧&quot;模拟知识库&quot;面板中：</p><ul><li>点击 <strong>&quot;＋&quot;</strong> 按钮添加文档片段</li><li>在弹出的编辑器中输入文档内容</li><li>重复以上步骤，建立你的微型知识库</li></ul><p>系统已预置了 12 条覆盖技术、科学和文化的示例文档，你可以直接体验。</p><h4 id="_2-一键向量化" tabindex="-1">2. 一键向量化 <a class="header-anchor" href="#_2-一键向量化" aria-label="Permalink to &quot;2. 一键向量化&quot;">​</a></h4><p>编辑完文档后，点击 <strong>&quot;一键向量化&quot;</strong> 按钮。系统会批量调用 Embedding API，为每篇文档生成向量。成功向量化的文档左侧会显示绿色边框标记。</p><h4 id="_3-执行检索" tabindex="-1">3. 执行检索 <a class="header-anchor" href="#_3-执行检索" aria-label="Permalink to &quot;3. 执行检索&quot;">​</a></h4><p>在右侧的检索区域：</p><ol><li>输入你的查询语句，例如 <code>&quot;如何构建桌面应用程序？&quot;</code></li><li>配置检索参数： <ul><li><strong>Top-K</strong>：返回前 N 条匹配结果</li><li><strong>相似度算法</strong>：选择距离计算方式</li><li><strong>搜索阈值</strong>：通过滑块设定相似度下限，低于此分数的结果将被过滤</li></ul></li><li>按回车或点击 <strong>&quot;检索&quot;</strong> 按钮</li></ol><h4 id="_4-查看召回结果" tabindex="-1">4. 查看召回结果 <a class="header-anchor" href="#_4-查看召回结果" aria-label="Permalink to &quot;4. 查看召回结果&quot;">​</a></h4><p>右侧会展示命中的文档卡片，包含：</p><ul><li><strong>排名标记</strong>（TOP 1 / TOP 2 ...）</li><li><strong>相似度百分比</strong> 和进度条</li><li><strong>文档原文内容</strong></li></ul><p><strong>💡 小技巧</strong>：当知识库向量化完成后，你可以修改查询语句反复测试召回效果，系统会自动缓存查询向量，避免重复请求。切换算法或调整 Top-K 后，结果会基于缓存自动重算。</p><hr><h3 id="🔧-基础调试" tabindex="-1">🔧 基础调试 <a class="header-anchor" href="#🔧-基础调试" aria-label="Permalink to &quot;🔧 基础调试&quot;">​</a></h3><p>这是最&quot;硬核&quot;的面板——直接面向 Embedding API 的原始请求和响应。</p><p><strong>典型使用场景</strong>：</p><ul><li><strong>协议对接</strong>：刚接入了一个新的 Embedding 模型，想确认 API 是否正常工作</li><li><strong>维度验证</strong>：需要确认模型的实际输出维度是否与文档一致</li><li><strong>性能测试</strong>：想估算单次 Embedding 请求的耗时和 Token 消耗</li></ul><p><strong>特殊功能 —— 自定义维度</strong>：</p><p>对于支持可变维度的模型（如 OpenAI 的 <code>text-embedding-3</code> 系列），你可以在&quot;维度&quot;选择器中指定目标维度（支持 256、512、1024 等常见值）。用更小的维度意味着更低的存储开销和更快的检索速度，但会损失部分精度。</p><p><strong>运行结果面板包含</strong>：</p><ul><li><strong>向量预览</strong>：自动截取向量的首尾各 5 个数值，让你快速感知数值分布范围</li><li><strong>统计指标</strong>：实际输出维度 + Token 消耗量 + 请求耗时（ms）</li><li><strong>完整响应 JSON</strong>：展示完整的 API 原生响应体，支持高亮和只读浏览</li></ul><hr><h2 id="高级用法" tabindex="-1">高级用法 <a class="header-anchor" href="#高级用法" aria-label="Permalink to &quot;高级用法&quot;">​</a></h2><h3 id="增量缓存加速" tabindex="-1">增量缓存加速 <a class="header-anchor" href="#增量缓存加速" aria-label="Permalink to &quot;增量缓存加速&quot;">​</a></h3><p><strong>相似度对比</strong>面板内置了一个按模型隔离的增量缓存系统。</p><p>当你对同一组文本反复进行对比时（比如切换不同算法对比结果），系统只会对 <strong>新增或修改过的文本</strong> 发起 API 请求，已缓存的文本直接从内存中读取。这意味着：</p><ul><li>第二次及以后的操作几乎 <strong>零延迟</strong></li><li>多次切换算法 <strong>不产生额外 API 开销</strong></li><li>换了模型后缓存自动隔离，<strong>不会跨模型混用</strong></li></ul><h3 id="对比报告导出" tabindex="-1">对比报告导出 <a class="header-anchor" href="#对比报告导出" aria-label="Permalink to &quot;对比报告导出&quot;">​</a></h3><p>在相似度对比的结果面板中，点击复制按钮可以获得格式化的文本报告，包含：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>语义相似度排行 (算法: cosine)</span></span>
<span class="line"><span>基准文本: 计算机科学</span></span>
<span class="line"><span></span></span>
<span class="line"><span>#1 [0.8921] 机器学习</span></span>
<span class="line"><span>#2 [0.8514] 深度学习</span></span>
<span class="line"><span>#3 [0.8123] 神经网络</span></span>
<span class="line"><span>...</span></span></code></pre></div><p>方便你记录到笔记或分享给团队成员。</p><h3 id="不同算法的最佳实践" tabindex="-1">不同算法的最佳实践 <a class="header-anchor" href="#不同算法的最佳实践" aria-label="Permalink to &quot;不同算法的最佳实践&quot;">​</a></h3><table tabindex="0"><thead><tr><th>算法</th><th>适用场景</th><th>注意事项</th></tr></thead><tbody><tr><td>余弦相似度</td><td>通用语义对比（最常用）</td><td>忽略向量绝对长度，只关注方向</td></tr><tr><td>点积</td><td>已归一化向量</td><td>结果受向量长度影响</td></tr><tr><td>欧氏距离</td><td>需要关注数值绝对差异</td><td>已自动转换为相似度分数</td></tr><tr><td>曼哈顿距离</td><td>高维空间稀疏向量</td><td>已自动转换为相似度分数</td></tr></tbody></table><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="为什么点击-开始对比-后没有反应" tabindex="-1">为什么点击&quot;开始对比&quot;后没有反应？ <a class="header-anchor" href="#为什么点击-开始对比-后没有反应" aria-label="Permalink to &quot;为什么点击&quot;开始对比&quot;后没有反应？&quot;">​</a></h3><p>最常见的原因是<strong>没有选择 Embedding 模型</strong>。请确保：</p><ol><li>在设置中配置了至少一个 LLM Profile</li><li>该 Profile 中包含了支持 Embedding 能力的模型</li><li>在工具顶部的模型选择器中选中了该模型</li></ol><h3 id="不同-相似度算法-得出的排名为什么不一样" tabindex="-1">不同&quot;相似度算法&quot;得出的排名为什么不一样？ <a class="header-anchor" href="#不同-相似度算法-得出的排名为什么不一样" aria-label="Permalink to &quot;不同&quot;相似度算法&quot;得出的排名为什么不一样？&quot;">​</a></h3><p>这非常正常。不同的距离/相似度算法从不同角度衡量向量关系：</p><ul><li><strong>余弦相似度</strong> 关注语义方向的一致性</li><li><strong>欧氏距离</strong> 注重绝对位置相近度</li><li><strong>点积</strong> 则考虑了向量模长</li></ul><p>切换算法可以帮助你从多个维度理解模型的行为特征。</p><h3 id="检索模拟-中修改了文档-需要重新向量化吗" tabindex="-1">&quot;检索模拟&quot;中修改了文档，需要重新向量化吗？ <a class="header-anchor" href="#检索模拟-中修改了文档-需要重新向量化吗" aria-label="Permalink to &quot;&quot;检索模拟&quot;中修改了文档，需要重新向量化吗？&quot;">​</a></h3><p>是的。修改文档内容后，其向量表示会失效，需要重新执行&quot;一键向量化&quot;来更新索引。修改过的文档左侧的绿色边框会消失，提醒你需要重新向量化。</p><h3 id="目前支持哪些-embedding-模型" tabindex="-1">目前支持哪些 Embedding 模型？ <a class="header-anchor" href="#目前支持哪些-embedding-模型" aria-label="Permalink to &quot;目前支持哪些 Embedding 模型？&quot;">​</a></h3><p>只要在应用的 LLM 配置中添加了支持 Embedding 能力的模型，都可以在 Embedding 测试中使用。具体支持的模型列表取决于你的 LLM Provider 配置。</p><h3 id="在何处查看-api-key-和模型配置" tabindex="-1">在何处查看 API Key 和模型配置？ <a class="header-anchor" href="#在何处查看-api-key-和模型配置" aria-label="Permalink to &quot;在何处查看 API Key 和模型配置？&quot;">​</a></h3><p>请前往 <strong>应用设置 &gt; LLM 配置</strong> 中管理你的 Profile 和模型。</p>`,82)])])}const q=o(r,[["render",i]]);export{h as __pageData,q as default};
